fun solve(nums: Array<Long>, queries: Array<Array<Long>>): Long {
    val MOD = 1000000007
    val n = nums.size
    val multipliers = Array(n) { HashMap<Int, Long>() }

    for (query in queries) {
        val li = query[0].toLong().toInt()
        val ri = query[1].toLong().toInt()
        val ki = query[2].toLong().toInt()
        val vi = query[3].toLong().toInt()

        var current = li
        while (current <= ri) {
            multipliers[current][ki] = (multipliers[current][ki] ?: 1L) * vi % MOD
            current += ki
        }
    }

    var result = 0L
    for (i in 0 until n) {
        var val = nums[i]
        for ((step, factor) in multipliers[i].entries) {
            val = (val * factor) % MOD
        }
        result ^= val
    }

    return result
}
